import type { ParsedRule } from '../parse'

export function toClassName(rule: ParsedRule): string {
  return [...rule.v, (rule.i ? '!' : '') + rule.n].join(':')
}
import type {
  Twind,
  BaseTheme,
  TwindConfig,
  Sheet,
  TwindUserConfig,
  ExtractThemes,
  Preset,
} from './types'

import { twind } from './twind'
import { observe } from './observe'
import { getSheet } from './sheets'
import { noop } from './utils'
import { DEV } from 'distilt/env'

/**
 * @group Runtime
 * @param install
 * @returns
 */
export function auto(install: () => void): () => void {
  // If we run in the browser we call install at latest when the body is inserted
  // This algorith works well for _normal_ scripts (`<script src="..."></script>`)
  // but not for modules because those are executed __after__ the DOM is ready
  // and we would have FOUC
  if (typeof document != 'undefined' && document.currentScript) {
    const cancelAutoInstall = () => observer.disconnect()

    const observer: MutationObserver = new MutationObserver((mutationsList) => {
      for (const { target } of mutationsList) {
        // If we reach the body we immediately run the install to prevent FOUC
        if (target === document.body) {
          install()
          return cancelAutoInstall()
        }
      }
    })

    observer.observe(document.documentElement, {
      childList: true,
      subtree: true,
    })

    return cancelAutoInstall
  }

  return noop
}

let active: Twind

function assertActive() {
  if (DEV && !active) {
    throw new Error(
      `No active twind instance found. Make sure to call setup or install before accessing tw.`,
    )
  }
}

/**
 * A proxy to the currently active Twind instance.
 * @group Style Injectors
 */
export const tw: Twind<any, any> = /* #__PURE__ */ new Proxy(
  // just exposing the active as tw should work with most bundlers
  // as ES module export can be re-assigned BUT some bundlers to not honor this
  // -> using a delegation proxy here
  noop as unknown as Twind<any, any>,
  {
    apply(_target, _thisArg, args) {
      if (DEV) assertActive()

      return active(args[0])
    },
    get(target, property) {
      if (DEV) {
        // Workaround webpack accessing the prototype in dev mode
        if (!active && property in target) {
          // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
          return (target as any)[property]
        }

        assertActive()
      }

      const value = active[property as keyof Twind]

      if (typeof value === 'function') {
        return function () {
          if (DEV) assertActive()

          // eslint-disable-next-line prefer-rest-params
          return value.apply(active, arguments)
        }
      }

      return value
    },
  },
)

export type SheetFactory<SheetTarget = unknown> = () => Sheet<SheetTarget>

/**
 * Manages a single Twind instance — works in browser, Node.js, Deno, workers...
 *
 * @group Runtime
 * @param config
 * @param sheet
 * @param target
 * @returns
 */
export function setup<Theme extends BaseTheme = BaseTheme, SheetTarget = unknown>(
  config?: TwindConfig<Theme>,
  sheet?: Sheet<SheetTarget> | SheetFactory<SheetTarget>,
  target?: HTMLElement,
): Twind<Theme, SheetTarget>

export function setup<
  Theme = BaseTheme,
  Presets extends Preset<any>[] = Preset[],
  SheetTarget = unknown,
>(
  config?: TwindUserConfig<Theme, Presets>,
  sheet?: Sheet<SheetTarget> | SheetFactory<SheetTarget>,
  target?: HTMLElement,
): Twind<BaseTheme & ExtractThemes<Theme, Presets>, SheetTarget>

export function setup<Theme extends BaseTheme = BaseTheme, SheetTarget = unknown>(
  config: TwindConfig<any> | TwindUserConfig<any> = {},
  sheet: Sheet<SheetTarget> | SheetFactory<SheetTarget> = getSheet as SheetFactory<SheetTarget>,
  target?: HTMLElement,
): Twind<Theme, SheetTarget> {
  active?.destroy()

  active = observe(
    twind(config as TwindUserConfig, typeof sheet == 'function' ? sheet() : sheet),
    target,
  )

  return active as unknown as Twind<Theme, SheetTarget>
}
import type { ParsedRule } from '../parse'
import { toClassName } from './to-class-name'

export function format(rules: ParsedRule[], seperator = ','): string {
  return rules.map(toClassName).join(seperator)
}
import type { MaybeArray, ScreenValue } from './types'

/**
 * @internal
 */
export const escape =
  (typeof CSS !== 'undefined' && CSS.escape) ||
  // Simplified: escaping only special characters
  // Needed for NodeJS and Edge <79 (https://caniuse.com/mdn-api_css_escape)
  ((className: string): string =>
    className
      // Simplifed escape testing only for chars that we know happen to be in tailwind directives
      .replace(/[!"'`*+.,;:\\/<=>?@#$%&^|~()[\]{}]/g, '\\$&')
      // If the character is the first character and is in the range [0-9] (2xl, ...)
      // https://drafts.csswg.org/cssom/#escape-a-character-as-code-point
      .replace(/^\d/, '\\3$& '))

// Based on https://stackoverflow.com/a/52171480
/**
 * @group Configuration
 * @param value
 * @returns
 */
export function hash(value: string): string {
  // eslint-disable-next-line no-var
  for (var h = 9, index = value.length; index--; ) {
    h = Math.imul(h ^ value.charCodeAt(index), 0x5f356495)
  }

  return '#' + ((h ^ (h >>> 9)) >>> 0).toString(36)
}

/**
 * @internal
 * @param screen
 * @param prefix
 * @returns
 */
export function mql(screen: MaybeArray<ScreenValue>, prefix = '@media '): string {
  return (
    prefix +
    asArray(screen)
      .map((screen) => {
        if (typeof screen == 'string') {
          screen = { min: screen }
        }

        return (
          (screen as { raw?: string }).raw ||
          Object.keys(screen)
            .map((feature) => `(${feature}-width:${(screen as Record<string, string>)[feature]})`)
            .join(' and ')
        )
      })
      .join(',')
  )
}

/**
 * @internal
 * @param value
 * @returns
 */
export function asArray<T>(value: T = [] as unknown as T): T extends Array<any> ? T : T[] {
  return (Array.isArray(value) ? value : value == null ? [] : [value]) as T extends Array<any>
    ? T
    : T[]
}

/**
 * @internal
 * @param value
 * @returns
 */
export function identity<T>(value: T): T {
  return value
}

/**
 * @internal
 */
export function noop(): void {
  // no-op
}
import type { BaseTheme, Context } from '../types'
import type { ParsedRule } from '../parse'
import { asArray, mql } from '../utils'
import { toClassName } from './to-class-name'

// Based on https://github.com/kripod/otion
// License MIT

// export const enum Shifts {
//   darkMode = 30,
//   layer = 27,
//   screens = 26,
//   responsive = 22,
//   atRules = 18,
//   variants = 0,
