import type { TwindRule } from '../types'
import { escape } from '../utils'

export function stringify(rule: TwindRule): string | undefined {
  if (rule.d) {
    const groups: string[] = []

    const selector = replaceEach(
      // merge all conditions into a selector string
      rule.r.reduce((selector, condition) => {
        if (condition[0] == '@') {
          groups.push(condition)
          return selector
        }

        // Go over the selector and replace the matching multiple selectors if any
        return condition ? merge(selector, condition) : selector
      }, '&'),
      // replace '&' with rule name or an empty string
      (selectorPart) => replaceReference(selectorPart, rule.n ? '.' + escape(rule.n) : ''),
    )

    if (selector) {
      groups.push(selector.replace(/:merge\((.+?)\)/g, '$1'))
    }

    return groups.reduceRight((body, grouping) => grouping + '{' + body + '}', rule.d)
  }
}

function replaceEach(selector: string, iteratee: (selectorPart: string) => string): string {
  return selector.replace(
    / *((?:\(.+?\)|\[.+?\]|[^,])+) *(,|$)/g,
    (_, selectorPart: string, comma: string) => iteratee(selectorPart) + comma,
  )
}

function replaceReference(selector: string, reference: string): string {
  return selector.replace(/&/g, reference)
}

function merge(selector: string, condition: string): string {
  return replaceEach(selector, (selectorPart) =>
    replaceEach(
      condition,
      // If the current condition has a nested selector replace it
      (conditionPart) => {
        const mergeMatch = /(:merge\(.+?\))(:[a-z-]+|\\[.+])/.exec(conditionPart)

        if (mergeMatch) {
          const selectorIndex = selectorPart.indexOf(mergeMatch[1])

          if (~selectorIndex) {
            // [':merge(.group):hover .rule', ':merge(.group):focus &'] -> ':merge(.group):focus:hover .rule'
            // ':merge(.group)' + ':focus' + ':hover .rule'
            return (
              selectorPart.slice(0, selectorIndex) +
              mergeMatch[0] +
              selectorPart.slice(selectorIndex + mergeMatch[1].length)
            )
          }

          // [':merge(.peer):focus~&', ':merge(.group):hover &'] -> ':merge(.peer):focus~:merge(.group):hover &'
          return replaceReference(selectorPart, conditionPart)
        }

        // Return the current selector with the key matching multiple selectors if any
        return replaceReference(conditionPart, selectorPart)
      },
    ),
  )
}
import { Layer } from './precedence'

const collator = new Intl.Collator('en', { numeric: true })

export interface SortableRule {
  /** The calculated precedence taking all variants into account. */
  p: number

  /* The precedence of the properties within {@link d}. */
  o: number

  /** The name to use for `&` expansion in selectors. Maybe empty for at-rules like `@import`, `@font-face`, `@media`, ... */
  n?: string | null
}

/**
 * Find the array index of where to add an element to keep it sorted.
 *
 * @returns The insertion index
 */
export function sortedInsertionIndex(
  array: readonly SortableRule[],
  element: SortableRule,
): number {
  // Find position using binary search
  // eslint-disable-next-line no-var
  for (var low = 0, high = array.length; low < high; ) {
    const pivot = (high + low) >> 1

    // Less-Then-Equal to add new equal element after all existing equal elements (stable sort)
    if (compareTwindRules(array[pivot], element) <= 0) {
      low = pivot + 1
    } else {
      high = pivot
    }
  }

  return high
}

export function compareTwindRules(a: SortableRule, b: SortableRule): number {
  // base and overrides (css) layers are kept in order they are declared
  const layer = a.p & Layer.o

  if (layer == (b.p & Layer.o) && (layer == Layer.b || layer == Layer.o)) {
    return 0
  }

  return (
    a.p - b.p ||
    a.o - b.o ||
    collator.compare(byModifier(a.n), byModifier(b.n)) ||
    collator.compare(byName(a.n), byName(b.n))
  )
}

function byModifier(s: string | null | undefined) {
  return ((s || '').split(/:/).pop() as string).split('/').pop() || '\x00'
}

function byName(s: string | null | undefined) {
  return (s || '').replace(/\W/g, (c) => String.fromCharCode(127 + c.charCodeAt(0))) + '\x00'
}
import type { ColorValue, ColorFunctionOptions, Context, Falsey } from './types'

function parseColorComponent(chars: string, factor: number): number {
  return Math.round(parseInt(chars, 16) * factor)
}

/**
 * @internal
 * @param color
 * @param options
 * @returns
 */
export function toColorValue(color: ColorValue, options: ColorFunctionOptions = {}): string {
  if (typeof color == 'function') {
    return color(options)
  }

  const { opacityValue = '1', opacityVariable } = options
  const opacity = opacityVariable ? `var(${opacityVariable})` : opacityValue

  if (color.includes('<alpha-value>')) {
    return color.replace('<alpha-value>', opacity)
  }

  // rgb hex: #0123 and #001122
  if (color[0] == '#' && (color.length == 4 || color.length == 7)) {
    const size = (color.length - 1) / 3
    const factor = [17, 1, 0.062272][size - 1]

    return `rgba(${[
      parseColorComponent(color.substr(1, size), factor),
      parseColorComponent(color.substr(1 + size, size), factor),
      parseColorComponent(color.substr(1 + 2 * size, size), factor),
      opacity,
    ]})`
  }

  if (opacity == '1') return color
  if (opacity == '0') return '#0000'

  // convert rgb and hsl to alpha variant
  return color.replace(/^(rgb|hsl)(\([^)]+)\)$/, `$1a$2,${opacity})`)
}

/**
 * Looks for a matching dark color within a [tailwind color palette](https://tailwindcss.com/docs/customizing-colors) (`50`, `100`, `200`, ..., `800`, `900`).
 *
 * ```js
 * defineConfig({
 *   darkColor: autoDarkColor,
 * })
 * ```
 *
 * **Note**: Does not work for arbitrary values like `[theme(colors.gray.500)]` or `[theme(colors.gray.500, #ccc)]`.
 *
 * @group Configuration
 * @param section within theme to use
 * @param key of the light color or an arbitrary value
 * @param context to use
 * @returns the dark color if found
 */
export function autoDarkColor(
  section: string,
  key: string,
  { theme }: Context<any>,
): ColorValue | Falsey {
  // 50 -> 900, 100 -> 800, ..., 800 -> 100, 900 -> 50
  // key: gray-50, gray.50
  key = key.replace(
    /\d+$/,
    (shade) =>
      // ~~(parseInt(shade, 10) / 100): 50 -> 0, 900 -> 9
      // (9 - 0) -> 900, (9 - 9) -> 50
      ((9 - ~~(parseInt(shade, 10) / 100) || 0.5) * 100) as any,
  )

  return theme(section as 'colors', key)
}
