export function define(
  className: string,
  layer: number,
  rules: Falsey | ParsedRule[],
  useOrderOfRules?: boolean,
): string {
  return register(className, (rule, context) => {
    const { n: name, p: precedence, r: conditions, i: important } = convert(rule, context, layer)

    return (
      rules &&
      translateWith(
        name as string,
        layer,
        rules,
        context,
        precedence,
        conditions,
        important,
        useOrderOfRules,
      )
    )
  })
}
