export interface ParsedRule {
  /**
   * The utility name including `-` if set, but without `!` and variants
   */
  readonly n: string

  /**
   * All variants without trailing colon: `hover`, `after:`, `[...]`
   */
  readonly v: string[]

  /**
   * Something like `!underline` or `!bg-red-500` or `!red-500`
   */
  readonly i?: boolean
}

export interface ParsedDevRule extends ParsedRule {
  readonly a: string[]
  readonly l: [start: number, end: number]
}

function createRule(
  active: string[],
  current: ParsedRule[][],
  loc?: ParsedDevRule['l'] | false,
): void {
  if (active[active.length - 1] != '(') {
    const variants: string[] = []
    let important = false
    let negated = false
    let name = ''

    for (let value of active) {
      if (value == '(' || /[~@]$/.test(value)) continue

      if (value[0] == '!') {
        value = value.slice(1)
        important = !important
      }

      if (value.endsWith(':')) {
        variants[value == 'dark:' ? 'unshift' : 'push'](value.slice(0, -1))
        continue
      }

      if (value[0] == '-') {
        value = value.slice(1)
        negated = !negated
      }

      if (value.endsWith('-')) {
        value = value.slice(0, -1)
      }

      if (value && value != '&') {
        name += (name && '-') + value
      }
    }

    if (name) {
      if (negated) name = '-' + name

      current[0].push(
        DEV
          ? Object.defineProperties(
              { n: name, v: variants.filter(uniq), i: important },
              {
                a: { value: [...active] },
                l: { value: loc },
              },
            )
          : { n: name, v: variants.filter(uniq), i: important },
      )
    }
  }
}

function uniq<T>(value: T, index: number, values: T[]): boolean {
  return values.indexOf(value) == index
}

const cache = new Map<string, ParsedRule[]>()

/**
 * @internal
 * @param token
 * @returns
 */
export function parse(token: string): ParsedRule[] {
  let parsed = cache.get(token)

  if (!parsed) {
    // Stack of active groupings (`(`), variants, or nested (`~` or `@`)
    const active: string[] = []

    // Stack of current rule list to put new rules in
    // the first `0` element is the current list
    const current: ParsedRule[][] = [[]]

    let startIndex = 0
    let skip = 0
    let comment: RegExp | null = null
    let position = 0

    // eslint-disable-next-line no-inner-declarations
    const commit = (isRule?: boolean, endOffset = 0) => {
      if (startIndex != position) {
        active.push(token.slice(startIndex, position + endOffset))

        if (isRule) {
          createRule(active, current, DEV && [startIndex, position + endOffset])
        }
      }
      startIndex = position + 1
    }

    for (; position < token.length; position++) {
      const char = token[position]

      if (skip) {
        // within [...]
        // skip over until not skipping
        // ignore escaped chars
        if (token[position - 1] != '\\') {
          skip += +(char == '[') || -(char == ']')
        }
      } else if (char == '[') {
        // start to skip
        skip += 1
      } else if (comment) {
        if (token[position - 1] != '\\' && comment.test(token.slice(position))) {
          comment = null
          startIndex = position + RegExp.lastMatch.length
        }
      } else if (
        char == '/' &&
        token[position - 1] != '\\' &&
        (token[position + 1] == '*' || token[position + 1] == '/')
      ) {
        // multiline or single line comment
        comment = token[position + 1] == '*' ? /^\*\// : /^[\r\n]/
      } else if (char == '(') {
        // hover:(...) or utilitity-(...)
        commit()
        active.push(char)
      } else if (char == ':') {
        // hover: or after::
        if (token[position + 1] != ':') {
          commit(false, 1)
        }
      } else if (/[\s,)]/.test(char)) {
        // whitespace, comma or closing brace
        commit(true)

        let lastGroup = active.lastIndexOf('(')

        if (char == ')') {
          // Close nested block
          const nested = active[lastGroup - 1]

          if (/[~@]$/.test(nested)) {
            const rules = current.shift() as ParsedRule[]

            active.length = lastGroup

            // remove variants that are already applied through active
            createRule([...active, '#'], current, DEV && [startIndex, position])
            const { v } = current[0].pop() as ParsedRule

            for (const rule of rules) {
              // if a rule has dark we need to splice after the first entry eg dark
              rule.v.splice(+(rule.v[0] == 'dark') - +(v[0] == 'dark'), v.length)
            }

            createRule(
              [
                ...active,
                define(
                  // named nested
                  nested.length > 1
                    ? nested.slice(0, -1) + hash(JSON.stringify([nested, rules]))
                    : nested + '(' + format(rules) + ')',
                  Layer.a,
                  rules,
                  /@$/.test(nested),
                ),
              ],
              current,
              DEV && [startIndex, position],
            )
          }

          lastGroup = active.lastIndexOf('(', lastGroup - 1)
        }

        active.length = lastGroup + 1
      } else if (/[~@]/.test(char) && token[position + 1] == '(') {
        // start nested block
        // ~(...) or button~(...)
        // @(...) or button@(...)
        current.unshift([])
      }
    }

    // Consume remaining stack
    commit(true)

    cache.set(token, (parsed = current[0]))
  }

  return parsed
}
export function interleave<Interpolations>(
  strings: TemplateStringsArray,
  interpolations: readonly Interpolations[],
  handle: (interpolation: Interpolations) => string,
): string {
  return interpolations.reduce(
    (result: string, interpolation, index) => result + handle(interpolation) + strings[index + 1],
    strings[0],
  )
}
import type { Class } from '../types'
import { interleave } from './interleave'

// based on https://github.com/lukeed/clsx and https://github.com/jorgebucaran/classcat
export function interpolate(
  strings: TemplateStringsArray | Class,
  interpolations: Class[],
): string {
  return Array.isArray(strings) && Array.isArray((strings as unknown as TemplateStringsArray).raw)
    ? interleave(strings as unknown as TemplateStringsArray, interpolations, (value) =>
        toString(value).trim(),
      )
    : interpolations
        .filter(Boolean)
        .reduce(
          (result: string, value) => result + toString(value),
          strings ? toString(strings as Class) : '',
        )
}

function toString(value: Class): string {
  let result = ''
  let tmp: string

  if (value && typeof value == 'object') {
    if (Array.isArray(value)) {
      if ((tmp = interpolate(value[0], value.slice(1)))) {
        result += ' ' + tmp
      }
    } else {
      for (const key in value) {
        if (value[key]) result += ' ' + key
      }
    }
  } else if (value != null && typeof value != 'boolean') {
    result += ' ' + value
  }

  return result
}
import type { Class, Nested } from './types'
import { format } from './internal/format'
import { parse } from './parse'
import { interpolate } from './internal/interpolate'

/**
 * @group Class Name Generators
 */
export const apply = /* #__PURE__ */ alias('@')

/**
 * @group Class Name Generators
 */
export const shortcut = /* #__PURE__ */ alias('~')

function alias(marker: string): Nested {
  return new Proxy(
    function alias(strings: TemplateStringsArray | Class, ...interpolations: Class[]): string {
      return alias$('', strings, interpolations)
    } as Nested,
    {
      get(target, name) {
        if (name in target) return target[name as string]

        return function namedAlias(
          strings: TemplateStringsArray | Class,
          ...interpolations: Class[]
        ): string {
          return alias$(name as string, strings, interpolations)
        }
      },
    },
  )

  function alias$(
    name: string,
    strings: TemplateStringsArray | Class,
    interpolations: Class[],
  ): string {
    return format(parse(name + marker + '(' + interpolate(strings, interpolations) + ')'))
  }
}
import type { CSSObject, CSSValue } from '../types'
import { interleave } from './interleave'

export function astish(
  strings: CSSObject | string | TemplateStringsArray,
  interpolations: readonly CSSValue[],
): CSSObject[] {
  return Array.isArray(strings)
    ? astish$(
        interleave(strings as TemplateStringsArray, interpolations, (interpolation) =>
          interpolation != null && typeof interpolation != 'boolean'
            ? (interpolation as unknown as string)
            : '',
        ),
      )
    : typeof strings == 'string'
    ? astish$(strings)
    : [strings as CSSObject]
}

// Based on https://github.com/cristianbote/goober/blob/master/src/core/astish.js
const newRule = / *(?:(?:([\u0080-\uFFFF\w-%@]+) *:? *([^{;]+?);|([^;}{]*?) *{)|(}))/g

/**
 * Convert a css style string into a object
 */
function astish$(css: string): CSSObject[] {
  css = removeComments(css)

  const tree: CSSObject[] = [{}]
  const rules: CSSObject[] = [tree[0]]
  const conditions: string[] = []
  let block: RegExpExecArray | null

  while ((block = newRule.exec(css))) {
    // Remove the current entry
    if (block[4]) {
      tree.shift()
      conditions.shift()
    }

    if (block[3]) {
      // new nested
      conditions.unshift(block[3])
      tree.unshift({})
      rules.push(conditions.reduce((body, condition) => ({ [condition]: body }), tree[0]))
    } else if (!block[4]) {
      // if we already have that property — start a new CSSObject
      if (tree[0][block[1]]) {
        tree.unshift({})
        rules.push(conditions.reduce((body, condition) => ({ [condition]: body }), tree[0]))
      }
      tree[0][block[1]] = block[2]
    }
  }

  // console.log(rules)
  return rules
}

// Remove comments (multiline and single line)
function removeComments(css: string): string {
  return css.replace(/\/\*[^]*?\*\/|\s\s+|\n/gm, ' ')
}
import type { CSSObject, CSSValue } from './types'

import { register } from './internal/registry'
import { serialize } from './internal/serialize'
import { hash } from './utils'
import { Layer } from './internal/precedence'
import { merge } from './internal/merge'
import { astish } from './internal/astish'

/**
 * @group Class Name Generators
 * @param strings
 * @param interpolations
 */
export function css(strings: TemplateStringsArray, ...interpolations: readonly CSSValue[]): string

export function css(style: CSSObject | string): string

export function css(
  strings: CSSObject | string | TemplateStringsArray,
  ...interpolations: readonly CSSValue[]
): string {
  const ast = astish(strings, interpolations)

  const className = (ast.find((o) => o.label)?.label || 'css') + hash(JSON.stringify(ast))

  return register(className, (rule, context) =>
    merge(
      ast.flatMap((css) => serialize(css, rule, context, Layer.o)),
      className,
    ),
  )
}
import type { CSSObject, CSSProperties, StringLike } from './types'

import { css } from './css'

export interface AnimationFunction {
  (animation: string | CSSProperties, waypoints: StringLike): StringLike
}

export type Animation = AnimationFunction & {
  [label: string]: AnimationFunction
}

/**
 * @group Class Name Generators
 */
export const animation = /* #__PURE__ */ new Proxy(
  function animation(animation: string | CSSProperties, waypoints: StringLike): StringLike {
    return animation$('animation', animation, waypoints)
  } as Animation,
  {
    get(target, name) {
      if (name in target) return target[name as string]

      return function namedAnimation(
        animation: string | CSSProperties,
        waypoints: StringLike,
      ): StringLike {
        return animation$(name as string, animation, waypoints)
      }
    },
  },
)

function animation$(
  label: string,
  animation: string | CSSProperties,
  waypoints: StringLike,
): StringLike {
  return {
    toString() {
      return css({
        label,
        '@layer components': {
          ...(typeof animation == 'object' ? animation : { animation }),
          animationName: '' + waypoints,
        },
      } as CSSObject)
    },
  } as StringLike
}
