      key ||= 'DEFAULT'

      const value =
        section[key] ?? key.split('-').reduce((obj, prop) => obj?.[prop], section) ?? defaultValue

      return opacityValue
        ? toColorValue(value, { opacityValue: resolveThemeFunction(opacityValue, theme) })
        : value
